class Solution:
    def checkValidCuts(self, n, rectangles):
        def check(lo_of, hi_of):
            coords = {0, n}
            for r in rectangles:
                coords.add(lo_of(r))
                coords.add(hi_of(r))
            candidates = sorted(coords)
            m = len(candidates)
            for i in range(m):
                for j in range(i + 1, m):
                    c1, c2 = candidates[i], candidates[j]
                    if c1 <= 0 or c2 >= n or c1 >= c2:
                        continue
                    sec1 = sec2 = sec3 = 0
                    ok = True
                    for r in rectangles:
                        lo, hi = lo_of(r), hi_of(r)
                        if lo < c1 < hi or lo < c2 < hi:
                            ok = False
                            break
                        if hi <= c1:
                            sec1 += 1
                        elif hi <= c2:
                            sec2 += 1
                        else:
                            sec3 += 1
                    if ok and sec1 > 0 and sec2 > 0 and sec3 > 0:
                        return True
            return False

        y_ok = check(lambda r: r[1], lambda r: r[3])
        x_ok = check(lambda r: r[0], lambda r: r[2])
        return y_ok or x_ok

